// Inline font dictionary for carousel slides.
// Real WOFF2 base64 — Google Fonts latin subset, downloaded 2026-06-23.
// Inter v20 variable (covers weight 100-900). Playfair Display v40 (two weights).
// FONT_DICT lives in its own file to keep slideHtml.ts readable.
export const FONT_DICT: Record<string, string> = {
  'Inter':                    '',
  'Playfair Display':         '',
  'Playfair Display Bold':    '',
}

// Generates @font-face declarations for the named fonts that have entries in
// FONT_DICT. Unknown font names are silently skipped (falls back to system font).
export function buildFontFaceBlock(fontNames: string[]): string {
  return fontNames
    .filter(f => FONT_DICT[f])
    .map(f => {
      const family = f.replace(' Bold', '')
      const weight = f.includes('Bold') ? '700 900' : '100 700'
      return `@font-face{font-family:'${family}';src:url('data:font/woff2;base64,${FONT_DICT[f]}') format('woff2');font-weight:${weight};font-style:normal;font-display:block;}`
    })
    .join('\n')
}
